import{_ as e,c as a,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"버전 로그: 기능 업데이트 | OpenSkills","description":"OpenSkills 버전 변경 내역을 확인하고, update 명령, 심볼릭 링크, 프라이빗 저장소 등의 새 기능과 경로 순회 보호 등 중요한 개선 사항 및 문제 해결을 알아보세요.","frontmatter":{"title":"버전 로그: 기능 업데이트 | OpenSkills","sidebarTitle":"새 기능 보기","subtitle":"버전 로그: 기능 업데이트 | OpenSkills","description":"OpenSkills 버전 변경 내역을 확인하고, update 명령, 심볼릭 링크, 프라이빗 저장소 등의 새 기능과 경로 순회 보호 등 중요한 개선 사항 및 문제 해결을 알아보세요.","tags":["changelog","version history"],"order":1},"headers":[],"relativePath":"ko/numman-ali/openskills/changelog/changelog/index.md","filePath":"ko/numman-ali/openskills/changelog/changelog/index.md"}'),r={name:"ko/numman-ali/openskills/changelog/changelog/index.md"};function t(n,l,s,d,h,c){return i(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="변경-로그" tabindex="-1">변경 로그 <a class="header-anchor" href="#변경-로그" aria-label="Permalink to &quot;변경 로그&quot;">​</a></h1><p>이 페이지는 OpenSkills의 버전 변경 내역을 기록하며, 각 버전의 새로운 기능, 개선 사항 및 문제 해결 내용을 확인할 수 있습니다.</p><hr><h2 id="_1-5-0-2026-01-17" tabindex="-1">[1.5.0] - 2026-01-17 <a class="header-anchor" href="#_1-5-0-2026-01-17" aria-label="Permalink to &quot;[1.5.0] - 2026-01-17&quot;">​</a></h2><h3 id="새로운-기능" tabindex="-1">새로운 기능 <a class="header-anchor" href="#새로운-기능" aria-label="Permalink to &quot;새로운 기능&quot;">​</a></h3><ul><li><strong><code>openskills update</code></strong> - 기록된 소스에서 설치된 스킬을 새로고침합니다 (기본값: 모두 새로고침)</li><li><strong>소스 메타데이터 추적</strong> - 설치 시 소스 정보를 기록하여 스킬을 안정적으로 업데이트할 수 있습니다</li></ul><h3 id="개선-사항" tabindex="-1">개선 사항 <a class="header-anchor" href="#개선-사항" aria-label="Permalink to &quot;개선 사항&quot;">​</a></h3><ul><li><strong>다중 스킬 읽기</strong> - <code>openskills read</code> 명령이 이제 쉼표로 구분된 스킬 이름 목록을 지원합니다</li><li><strong>사용 안내 생성</strong> - 셸 환경에서 read 명령 호출 안내를 최적화했습니다</li><li><strong>README</strong> - 업데이트 가이드와 수동 사용 안내를 추가했습니다</li></ul><h3 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h3><ul><li><strong>업데이트 경험 개선</strong> - 소스 메타데이터가 없는 스킬은 건너뛰고, 해당 스킬 목록을 표시하여 재설치를 안내합니다</li></ul><hr><h2 id="_1-4-0-2026-01-17" tabindex="-1">[1.4.0] - 2026-01-17 <a class="header-anchor" href="#_1-4-0-2026-01-17" aria-label="Permalink to &quot;[1.4.0] - 2026-01-17&quot;">​</a></h2><h3 id="개선-사항-1" tabindex="-1">개선 사항 <a class="header-anchor" href="#개선-사항-1" aria-label="Permalink to &quot;개선 사항&quot;">​</a></h3><ul><li><strong>README</strong> - 프로젝트 로컬 기본 설치 방식을 명확히 하고, 중복된 sync 안내를 제거했습니다</li><li><strong>설치 메시지</strong> - 설치 프로그램이 이제 프로젝트 로컬 기본 설치와 <code>--global</code> 옵션을 명확히 구분합니다</li></ul><hr><h2 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h2><h3 id="개선-사항-2" tabindex="-1">개선 사항 <a class="header-anchor" href="#개선-사항-2" aria-label="Permalink to &quot;개선 사항&quot;">​</a></h3><ul><li><strong>문서와 AGENTS.md 가이드</strong> - 모든 명령 예제와 생성된 사용 안내를 <code>npx openskills</code>로 통일했습니다</li></ul><hr><h2 id="_1-3-1-2026-01-17" tabindex="-1">[1.3.1] - 2026-01-17 <a class="header-anchor" href="#_1-3-1-2026-01-17" aria-label="Permalink to &quot;[1.3.1] - 2026-01-17&quot;">​</a></h2><h3 id="문제-해결-1" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결-1" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h3><ul><li><strong>Windows 설치</strong> - Windows 시스템의 경로 검증 문제를 수정했습니다 (&quot;Security error: Installation path outside target directory&quot;)</li><li><strong>CLI 버전</strong> - <code>npx openskills --version</code>이 이제 package.json의 버전 번호를 올바르게 읽습니다</li><li><strong>루트 디렉토리 SKILL.md</strong> - 저장소 루트 디렉토리의 SKILL.md로 단일 스킬 저장소 설치 문제를 수정했습니다</li></ul><hr><h2 id="_1-3-0-2025-12-14" tabindex="-1">[1.3.0] - 2025-12-14 <a class="header-anchor" href="#_1-3-0-2025-12-14" aria-label="Permalink to &quot;[1.3.0] - 2025-12-14&quot;">​</a></h2><h3 id="새로운-기능-1" tabindex="-1">새로운 기능 <a class="header-anchor" href="#새로운-기능-1" aria-label="Permalink to &quot;새로운 기능&quot;">​</a></h3><ul><li><p><strong>심볼릭 링크 지원</strong> - 스킬을 이제 심볼릭 링크를 통해 스킬 디렉토리에 설치할 수 있습니다 (<a href="https://github.com/numman-ali/openskills/issues/3" target="_blank" rel="noreferrer">#3</a>)</p><ul><li>복제된 저장소에서 심볼릭 링크를 생성하여 git 기반 스킬 업데이트를 지원합니다</li><li>로컬 스킬 개발 워크플로우를 지원합니다</li><li>손상된 심볼릭 링크는 자동으로 건너뜁니다</li></ul></li><li><p><strong>구성 가능한 출력 경로</strong> - sync 명령에 <code>--output</code> / <code>-o</code> 옵션이 추가되었습니다 (<a href="https://github.com/numman-ali/openskills/issues/5" target="_blank" rel="noreferrer">#5</a>)</p><ul><li>임의의 <code>.md</code> 파일(예: <code>.ruler/AGENTS.md</code>)에 동기화할 수 있습니다</li><li>파일이 없으면 자동으로 파일을 생성하고 제목을 추가합니다</li><li>필요한 경우 중첩 디렉토리를 자동으로 생성합니다</li></ul></li><li><p><strong>로컬 경로 설치</strong> - 로컬 디렉토리에서 스킬을 설치할 수 있습니다 (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>절대 경로 지원 (<code>/path/to/skill</code>)</li><li>상대 경로 지원 (<code>./skill</code>, <code>../skill</code>)</li><li>물결표 확장 지원 (<code>~/my-skills/skill</code>)</li></ul></li><li><p><strong>프라이빗 git 저장소 지원</strong> - 프라이빗 저장소에서 스킬을 설치할 수 있습니다 (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>SSH URLs (<code>git@github.com:org/private-skills.git</code>)</li><li>인증이 포함된 HTTPS URLs</li><li>시스템 SSH 키를 자동으로 사용합니다</li></ul></li><li><p><strong>포괄적인 테스트 스위트</strong> - 6개 테스트 파일에 걸쳐 88개의 테스트</p><ul><li>심볼릭 링크 감지, YAML 구문 분석의 단위 테스트</li><li>install, sync 명령의 통합 테스트</li><li>완전한 CLI 워크플로우의 엔드-투-엔드 테스트</li></ul></li></ul><h3 id="개선-사항-3" tabindex="-1">개선 사항 <a class="header-anchor" href="#개선-사항-3" aria-label="Permalink to &quot;개선 사항&quot;">​</a></h3><ul><li><p><strong><code>--yes</code> 플래그가 이제 모든 프롬프트를 건너뜁니다</strong> - 완전 비대화형 모드, CI/CD에 적합합니다 (<a href="https://github.com/numman-ali/openskills/issues/6" target="_blank" rel="noreferrer">#6</a>)</p><ul><li>기존 스킬을 덮어쓸 때 프롬프트를 표시하지 않습니다</li><li>프롬프트를 건너뛸 때 <code>Overwriting: &lt;skill-name&gt;</code> 메시지를 표시합니다</li><li>모든 명령이 헤드리스 환경에서 실행될 수 있습니다</li></ul></li><li><p><strong>CI 워크플로우 재배치</strong> - 빌드 단계가 이제 테스트 전에 실행됩니다</p><ul><li>엔드-투-엔드 테스트를 위해 <code>dist/cli.js</code>가 존재하도록 합니다</li></ul></li></ul><h3 id="보안" tabindex="-1">보안 <a class="header-anchor" href="#보안" aria-label="Permalink to &quot;보안&quot;">​</a></h3><ul><li><strong>경로 순회 보호</strong> - 설치 경로가 대상 디렉토리 내에 있는지 검증합니다</li><li><strong>심볼릭 링크 역참조</strong> - <code>cpSync</code>는 <code>dereference: true</code>를 사용하여 심볼릭 링크 대상을 안전하게 복사합니다</li><li><strong>비탐욕적 YAML 정규식</strong> - frontmatter 구문 분석에서 잠재적인 ReDoS 공격을 방지합니다</li></ul><hr><h2 id="_1-2-1-2025-10-27" tabindex="-1">[1.2.1] - 2025-10-27 <a class="header-anchor" href="#_1-2-1-2025-10-27" aria-label="Permalink to &quot;[1.2.1] - 2025-10-27&quot;">​</a></h2><h3 id="문제-해결-2" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결-2" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h3><ul><li>README 문서 정리 - 중복 섹션과 잘못된 플래그를 제거했습니다</li></ul><hr><h2 id="_1-2-0-2025-10-27" tabindex="-1">[1.2.0] - 2025-10-27 <a class="header-anchor" href="#_1-2-0-2025-10-27" aria-label="Permalink to &quot;[1.2.0] - 2025-10-27&quot;">​</a></h2><h3 id="새로운-기능-2" tabindex="-1">새로운 기능 <a class="header-anchor" href="#새로운-기능-2" aria-label="Permalink to &quot;새로운 기능&quot;">​</a></h3><ul><li><code>--universal</code> 플래그, 스킬을 <code>.claude/skills/</code> 대신 <code>.agent/skills/</code>에 설치 <ul><li>다중 에이전트 환경(Claude Code + Cursor/Windsurf/Aider)에 적합합니다</li><li>Claude Code 네이티브 마켓플레이스 플러그인과의 충돌을 방지합니다</li></ul></li></ul><h3 id="개선-사항-4" tabindex="-1">개선 사항 <a class="header-anchor" href="#개선-사항-4" aria-label="Permalink to &quot;개선 사항&quot;">​</a></h3><ul><li>프로젝트 로컬 설치가 이제 기본 옵션입니다 (이전에는 전역 설치)</li><li>스킬은 기본적으로 <code>./.claude/skills/</code>에 설치됩니다</li></ul><hr><h2 id="_1-1-0-2025-10-27" tabindex="-1">[1.1.0] - 2025-10-27 <a class="header-anchor" href="#_1-1-0-2025-10-27" aria-label="Permalink to &quot;[1.1.0] - 2025-10-27&quot;">​</a></h2><h3 id="새로운-기능-3" tabindex="-1">새로운 기능 <a class="header-anchor" href="#새로운-기능-3" aria-label="Permalink to &quot;새로운 기능&quot;">​</a></h3><ul><li>기술적 심층 분석을 포함한 포괄적인 단일 페이지 README</li><li>Claude Code와의 병렬 비교</li></ul><h3 id="문제-해결-3" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결-3" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h3><ul><li>위치 라벨이 이제 설치 위치에 따라 <code>project</code> 또는 <code>global</code>을 올바르게 표시합니다</li></ul><hr><h2 id="_1-0-0-2025-10-26" tabindex="-1">[1.0.0] - 2025-10-26 <a class="header-anchor" href="#_1-0-0-2025-10-26" aria-label="Permalink to &quot;[1.0.0] - 2025-10-26&quot;">​</a></h2><h3 id="새로운-기능-4" tabindex="-1">새로운 기능 <a class="header-anchor" href="#새로운-기능-4" aria-label="Permalink to &quot;새로운 기능&quot;">​</a></h3><ul><li>초기 릴리스</li><li><code>npx openskills install &lt;source&gt;</code> - GitHub 저장소에서 스킬 설치</li><li><code>npx openskills sync</code> - AGENTS.md에 <code>&lt;available_skills&gt;</code> XML 생성</li><li><code>npx openskills list</code> - 설치된 스킬 표시</li><li><code>npx openskills read &lt;name&gt;</code> - 에이전트를 위한 스킬 콘텐츠 로드</li><li><code>npx openskills manage</code> - 대화형 스킬 삭제</li><li><code>npx openskills remove &lt;name&gt;</code> - 지정된 스킬 삭제</li><li>모든 명령의 대화형 TUI 인터페이스</li><li>Anthropic의 SKILL.md 형식 지원</li><li>점진적 공개(필요한 스킬만 로드)</li><li>리소스 패키징 지원(references/, scripts/, assets/)</li></ul><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스 코드 위치 보기</strong></summary><blockquote><p>업데이트 시간: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th></tr></thead><tbody><tr><td>변경 로그 원문</td><td><a href="https://github.com/numman-ali/openskills/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td></tr></tbody></table></details>',53)])])}const m=e(r,[["render",t]]);export{g as __pageData,m as default};
